import{c as e,Q as s,j as t,m as n}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Windows Optimisations","text":"Ultimate Performance Suite","tagline":"Comprehensive collection of scripts and tools to optimize Windows 10/11 for peak performance, gaming, and privacy.","actions":[{"theme":"brand","text":"Unattended Install","link":"/AUTOUNATTEND"},{"theme":"alt","text":"System Tweaks","link":"/TWEAKS"}],"image":{"src":"https://github.githubassets.com/images/modules/logos_page/GitHub-Mark.png","alt":"Windows Optimisations"}},"features":[{"title":"Performance First","details":"Registry tweaks for thread priority alignment, SSD alignments, network routing, and custom power plans.","icon":"🚀"},{"title":"Privacy & Telemetry","details":"Broad-spectrum telemetry disablement, background app execution filters, and Edge telemetry cleanups.","icon":"🔒"},{"title":"Seamless Automation","details":"All scripts now support zero-prompt unattended execution via the -Force flag.","icon":"🤖"},{"title":"Automated OS Setup","details":"autounattend.xml automation templates that bypass TPM, Secure Boot, and RAM restrictions automatically.","icon":"🛠️"}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),i={name:"index.md"};function o(r,a,l,p,c,d){return s(),t("div",null,[...a[0]||(a[0]=[n(`<p align="center"><a href="https://github.com/YTxFSGAMERz/Windows-Optimisations" target="_blank"><img src="https://img.shields.io/github/stars/YTxFSGAMERz/Windows-Optimisations?style=for-the-badge&amp;color=00bcd4&amp;logo=github" alt="Stars"></a><a href="https://github.com/YTxFSGAMERz/Windows-Optimisations/fork" target="_blank"><img src="https://img.shields.io/github/forks/YTxFSGAMERz/Windows-Optimisations?style=for-the-badge&amp;color=00bcd4&amp;logo=github" alt="Forks"></a><a href="https://github.com/YTxFSGAMERz/Windows-Optimisations/blob/master/LICENSE" target="_blank"><img src="https://img.shields.io/badge/license-MIT-00bcd4?style=for-the-badge" alt="License"></a></p><div class="info custom-block"><p class="custom-block-title">Ultimate Windows Performance, Debloating, and Privacy Suite</p><p>Welcome to the official documentation site for the <strong>Windows Optimisations</strong> repository. This suite provides a curated, high-performance ecosystem of registry tweaks, automated installation files (<code>autounattend.xml</code>), toggle scripts, and utility configurations. Whether you want to boost gaming FPS, debloat background processes, or regain complete privacy on Windows 10/11, you&#39;ll find comprehensive step-by-step guides here.</p></div><hr><h2 id="👑-about-the-author" tabindex="-1">👑 About the Author <a class="header-anchor" href="#👑-about-the-author" aria-label="Permalink to &quot;👑 About the Author&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Farhan | Windows Optimization Specialist</p><p>Hi! I&#39;m <strong>Farhan</strong>, the designer and maintainer of this optimization catalog. My passion is to streamline Windows performance and eliminate background bloat, enabling high-responsiveness computing even on legacy hardware configurations.</p><ul><li>:octicons-mark-github-16: <strong>GitHub Profile:</strong> <a href="https://github.com/YTxFSGAMERz" target="_blank" rel="noreferrer">@YTxFSGAMERz</a></li><li>:fontawesome-brands-telegram: <strong>Telegram Channel:</strong> <a href="https://t.me/YTxFSGAMERz" target="_blank" rel="noreferrer">Telegram News Feed</a></li><li>:material-whatsapp: <strong>WhatsApp Direct:</strong> <a href="https://wa.me/917778906798" target="_blank" rel="noreferrer">WhatsApp Channel Support (+91 7778906798)</a></li></ul></div><hr><h2 id="📂-repository-layout" tabindex="-1">📂 Repository Layout <a class="header-anchor" href="#📂-repository-layout" aria-label="Permalink to &quot;📂 Repository Layout&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Windows-Optimisations/</span></span>
<span class="line"><span>├── Activators/                 # Activation utilities (MAS &amp; AAct)</span></span>
<span class="line"><span>├── Antivirus/                  # Lightweight, resident security installers (NOD32, Kaspersky, MalwareBytes)</span></span>
<span class="line"><span>├── Browsers/                   # Performance installers (Brave, Chrome, Firefox, Opera GX)</span></span>
<span class="line"><span>├── Core/                       # Framework Infrastructure (Logging, Snapshots, Restore)</span></span>
<span class="line"><span>├── Drivers/                    # Core hardware driver updaters (3DP Chip, Driver Booster)</span></span>
<span class="line"><span>├── Extra/                      # File compression, screenshotting, and TCP tuning tools</span></span>
<span class="line"><span>├── GUI/                        # XAML layout files for the WPF Dashboard</span></span>
<span class="line"><span>├── Hardware/                   # Monitoring tools (CPU-Z, GPU-Z, HWMonitor)</span></span>
<span class="line"><span>├── Launchers/                  # PowerShell controllers and initializers</span></span>
<span class="line"><span>├── Tools/                      # Standalone native performance utilities</span></span>
<span class="line"><span>├── Tweaks/                     # Primary registry modifications and scripts</span></span>
<span class="line"><span>│   ├── Appearance/             # Light/dark theme, transparency, Action Center, and Cortana</span></span>
<span class="line"><span>│   ├── Background/             # Telemetry background task execution filters</span></span>
<span class="line"><span>│   ├── Browser/                # Edge browser background telemetry removal</span></span>
<span class="line"><span>│   ├── Display/                # HDR keyboard bindings, graphics adjustments, GPU preferences</span></span>
<span class="line"><span>│   ├── Gaming/                 # Windows Game Mode configurations</span></span>
<span class="line"><span>│   ├── Network/                # Bandwidth throttle reduction registry tweaks</span></span>
<span class="line"><span>│   ├── Privacy/                # System permissions locks (Location, Camera, Microphone)</span></span>
<span class="line"><span>│   ├── Startup/                # Startup program management tools</span></span>
<span class="line"><span>│   ├── Storage/                # Temp cleaning scripts and Storage Sense tools</span></span>
<span class="line"><span>│   └── Windows/                # Core OS scheduler and task prioritization hooks</span></span>
<span class="line"><span>├── Windows Update/             # Instant toggle batch files for Windows Update</span></span>
<span class="line"><span>├── autounattend.xml            # Automated, pre-debloated Windows 11 setup XML</span></span>
<span class="line"><span>├── Start.bat                   # Core Zero-Friction GUI Launcher</span></span>
<span class="line"><span>├── CONTRIBUTING.md             # Guidelines for pull requests and adding modules</span></span>
<span class="line"><span>├── SECURITY.md                 # Vulnerability reporting protocols</span></span>
<span class="line"><span>├── CODE_OF_CONDUCT.md          # Open-source community guidelines</span></span>
<span class="line"><span>└── README.md                   # Home page</span></span></code></pre></div><hr><h2 id="🎯-guided-paths-by-use-case" tabindex="-1">🎯 Guided Paths by Use Case <a class="header-anchor" href="#🎯-guided-paths-by-use-case" aria-label="Permalink to &quot;🎯 Guided Paths by Use Case&quot;">​</a></h2><p>To help you get the most out of your optimization process, identify your use case below and follow the linked documentation paths:</p><h3 id="🎮-gamers-maximum-fps-low-latency" tabindex="-1">🎮 Gamers (Maximum FPS &amp; Low Latency) <a class="header-anchor" href="#🎮-gamers-maximum-fps-low-latency" aria-label="Permalink to &quot;🎮 Gamers (Maximum FPS &amp; Low Latency)&quot;">​</a></h3><ol><li>Apply CPU priorities and the custom power plan via <a href="./TWEAKS.html"><strong>System Tweaks</strong></a>.</li><li>Configure Message Signaled-Based Interrupts using the guide in <a href="./EXTRA.html"><strong>Extra Utilities</strong></a>.</li><li>Ensure display optimizations are active by consulting <a href="./TWEAKS.html#4-display-tweaks"><strong>Display Tweaks</strong></a>.</li><li>Update display and chipset drivers via <a href="./DRIVERS.html"><strong>Driver Management</strong></a>.</li></ol><h3 id="💻-legacy-low-end-pcs-8gb-ram-weak-cpus" tabindex="-1">💻 Legacy / Low-End PCs (&lt;8GB RAM &amp; Weak CPUs) <a class="header-anchor" href="#💻-legacy-low-end-pcs-8gb-ram-weak-cpus" aria-label="Permalink to &quot;💻 Legacy / Low-End PCs (&lt;8GB RAM &amp; Weak CPUs)&quot;">​</a></h3><ol><li>Turn off visual transparency and animations using <a href="./TWEAKS.html#1-appearance-tweaks"><strong>Appearance Tweaks</strong></a>.</li><li>Configure automatic RAM cleaning with <a href="./TWEAKS.html#memory-reduction"><strong>Mem Reduct Guide</strong></a>.</li><li>Switch update routines off using <a href="./WINDOWS_UPDATE.html"><strong>Windows Update Controls</strong></a> if you do not use the Microsoft Store.</li><li>Clean bloated caches using the <a href="./TWEAKS.html#11-storage-aggressive-tweaks"><strong>Aggressive Storage Cleanup</strong></a> guide.</li></ol><h3 id="🔒-privacy-minded-users-zero-telemetry" tabindex="-1">🔒 Privacy-Minded Users (Zero Telemetry) <a class="header-anchor" href="#🔒-privacy-minded-users-zero-telemetry" aria-label="Permalink to &quot;🔒 Privacy-Minded Users (Zero Telemetry)&quot;">​</a></h3><ol><li>Stop data collection routines using <a href="./TWEAKS.html#telemetry-data-collection"><strong>Telemetry Tweaks</strong></a>.</li><li>Restrict systemic access permissions via <a href="./TWEAKS.html#7-privacy-tweaks"><strong>Privacy Tweaks</strong></a>.</li><li>Transition to a telemetry-free browser by reading the <a href="./BROWSERS.html"><strong>Web Browsers Guide</strong></a>.</li><li>Consider performing a clean, fully-privatized OS setup using the <a href="./AUTOUNATTEND.html"><strong>Unattended Installation XML</strong></a>.</li></ol><hr><h2 id="⚠️-important-precautions" tabindex="-1">⚠️ Important Precautions <a class="header-anchor" href="#⚠️-important-precautions" aria-label="Permalink to &quot;⚠️ Important Precautions&quot;">​</a></h2><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><ul><li>Always perform a <strong>System Restore Point</strong> creation before running any scripts.</li><li>Some tweaks disable core security components (Windows Defender, SmartScreen). Only apply these modifications if you have alternative safeguards active or operate in secure isolated environments.</li><li>Read the <a href="./ANTIVIRUS.html"><strong>Antivirus Guide</strong></a> to understand recommended modern scanning setups.</li></ul></div><hr><p><em>For additional support or specific system optimization queries, join our Telegram Channel or contact Farhan directly.</em><em>Last updated: May 2026</em></p>`,22)])])}const h=e(i,[["render",o]]);export{u as __pageData,h as default};
